using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // [Breaking] EF 9 renamed discriminator from "Discriminator" to "$type".
            // Preserves compat with 500K existing docs and direct SQL (c.Discriminator).
            b.HasDiscriminator<string>("Discriminator");

            // [Breaking] EF 9 id no longer includes entity type prefix.
            // Preserves existing "Product|123" format in the JSON id property.
            b.HasDiscriminatorInJsonId();

            // [Breaking] EF 9 maps the CLR key directly to JSON id.
            // Preserves the EF 8 shadow-property approach so existing docs
            // (which store Id separately from the synthesized id) still load.
            b.HasShadowId();
        });
        // [Breaking] HasIndex removed — EF 9 Cosmos throws on HasIndex.
        // Cosmos indexes every property by default; manage custom policies via Azure Portal.
    }
}
